module RefModule (  
    input clk,  
    input reset,  
    input [7:0] seed,  
    output reg [7:0] lfsr_out  
);  
    wire unused_feedback;  
    assign unused_feedback = lfsr_out[7] ^ lfsr_out[5] ^ lfsr_out[4] ^ lfsr_out[3];  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            lfsr_out <= seed;  
        end else begin  
            lfsr_out <= {lfsr_out[6:0], unused_feedback};  
        end  
    end  
endmodule
